#include <bits/stdc++.h>using namespace std;#define int long long int#define all(x) x.begin(), x.end()const int MOD = 998244353; void solve() {    int n; cin >> n;    vector<int> a(n), dp(n + 1);    for (auto &x : a) cin >> x;    dp[n] = 1;    for (int i = n - 1; i >= 0; i--) {        vector<int> p(n - i);        int s = 0;        for (int j = 0; j < (n - i); j++) {            if (j) {                int k = p[j - 1];                while (k and a[i + j] != a[i + k]) k = p[k - 1];                if (a[i + j] == a[i + k]) k++;                p[j] = k;            }            if (!p[j]) {                s += dp[i + j + 1];                if (s >= MOD) s -= MOD;            }        }        dp[i] = s;    }    cout << dp[0] << '\n';}int32_t main() {    ios_base::sync_with_stdio(0); cin.tie(0);    int t = 1; cin >> t;    while (t--) solve();    return 0;}